                kind = type(v).__name__
                print(f"  {full}  ({kind}) = "
                      f"{json.dumps(v)[:100] if v else v}")
            walk(full, v)
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            walk(f"{prefix}[{i}]", v)

walk("", d)
